// slugify 函数 - 支持中文
function slugify(text: string): string {
  // 如果是中文，使用拼音或保留中文
  const hasChinese = /[\u4e00-\u9fa5]/.test(text);
  if (hasChinese) {
    // 中文工具使用英文名+随机数，或保留中文转义
    const base = text
      .replace(/[^\w\u4e00-\u9fa5\s-]/g, '')
      .replace(/\s+/g, '-')
      .substring(0, 30);
    return `${base}-${Math.random().toString(36).substring(2, 6)}`;
  }
  return text
    .toLowerCase()
    .replace(/[^\w\s-]/g, '')
    .replace(/\s+/g, '-')
    .substring(0, 50);
}

