async function main() {
  console.log('🚀 开始导入 AI 工具...\n');
  
  let successCount = 0;
  let skipCount = 0;
  let errorCount = 0;
  
  // 获取所有分类
  const categories = await prisma.category.findMany();
  const categoryMapByName = new Map(categories.map(c => [c.name, c.id]));
  
  console.log(`📊 数据库中有 ${categories.length} 个分类`);
  console.log(`📦 准备导入 ${mockTools.length} 个工具\n`);
  
  for (const tool of mockTools) {
    try {
      const categoryName = categoryMap[tool.category] || '其他工具';
      const categoryId = categoryMapByName.get(categoryName);
      
      if (!categoryId) {
        console.log(`⚠️  跳过: ${tool.name} - 分类 "${categoryName}" 不存在`);
        skipCount++;
        continue;
      }
      
      // 检查是否已存在
      const existing = await prisma.tool.findFirst({
        where: {
          OR: [
            { name: tool.name },
            { websiteUrl: tool.url },
          ],
        },
      });
      
      if (existing) {
        console.log(`⏭️  跳过: ${tool.name} - 已存在`);
        skipCount++;
        continue;
      }
      
      // 创建工具
      const slug = slugify(tool.name);
      await prisma.tool.create({
        data: {
          name: tool.name,
          slug,
          description: tool.description,
          shortDesc: tool.description,
          websiteUrl: tool.url,
          categoryId,
          pricingType: tool.pricing === 'free' ? 'FREE' : tool.pricing === 'paid' ? 'PAID' : 'FREEMIUM',
          tags: tool.tags.join(','),
          isActive: true,
          status: 'approved',
          isFeatured: Math.random() > 0.8, // 20% 设为推荐
          viewCount: Math.floor(Math.random() * 1000),
        },
      });
      
      console.log(`✅ 导入: ${tool.name} (${categoryName})`);
      successCount++;
    } catch (error) {
      console.error(`❌ 错误: ${tool.name} -`, error);
      errorCount++;
    }
  }
  
  console.log('\n📈 导入完成!');
  console.log(`   成功: ${successCount}`);
  console.log(`   跳过: ${skipCount}`);
  console.log(`   错误: ${errorCount}`);
  
  await prisma.$disconnect();
}

main().catch(console.error);
